18	namespace deep_ep::nccl {
19	
20	pybind11::bytearray get_local_unique_id() {
21	    ncclUniqueId unique_id;
22	    NCCL_CHECK(ncclGetUniqueId(&unique_id));
23	    std::vector<char> result(sizeof(ncclUniqueId));
24	    std::memcpy(result.data(), &unique_id, sizeof(ncclUniqueId));
25	    return {result.data(), result.size()};
26	}
27	
28	int64_t create_nccl_comm(const pybind11::bytearray& root_unique_id_bytes,
29	                         const int& num_ranks, const int& rank_idx) {
30	    // Copy unique ID
31	    ncclUniqueId root_unique_id;
32	    const auto root_unique_id_str = root_unique_id_bytes.cast<std::string>();
33	    std::memcpy(&root_unique_id, root_unique_id_str.c_str(), sizeof(ncclUniqueId));
34	
35	    // Init
36	    ncclComm_t comm;
37	    NCCL_CHECK(ncclCommInitRank(&comm, num_ranks, root_unique_id, rank_idx));
38	    if (get_env<int>("EP_BUFFER_DEBUG"))
39	        printf("New NCCL host communicator created (%d/%d)\n", rank_idx, num_ranks);
40	    return reinterpret_cast<int64_t>(comm);
41	}
42	
43	void destroy_nccl_comm(const int64_t& nccl_comm) {
44	    NCCL_CHECK(ncclCommAbort(reinterpret_cast<ncclComm_t>(nccl_comm)));
45	    if (get_env<int>("EP_BUFFER_DEBUG"))
46	        printf("NCCL host communicator aborted\n");
47	}
48	
49	std::tuple<int, int> get_physical_domain_size(const int64_t& nccl_comm) {
50	    const auto comm = reinterpret_cast<ncclComm_t>(nccl_comm);
51	    const int num_ranks = ncclTeamWorld(comm).nRanks, num_nvl_ranks = ncclTeamLsa(comm).nRanks;
52	    EP_HOST_ASSERT(num_ranks % num_nvl_ranks == 0);
53	    return {num_ranks / num_nvl_ranks, num_nvl_ranks};
54	}
55	
56	std::tuple<int, int> get_logical_domain_size(const int64_t& nccl_comm, const bool& allow_hybrid_mode) {
57	    const auto [num_rdma_ranks, num_nvl_ranks] = get_physical_domain_size(nccl_comm);
58	    return {allow_hybrid_mode ? num_rdma_ranks : 1,
59	            allow_hybrid_mode ? num_nvl_ranks : num_rdma_ranks * num_nvl_ranks};
60	}
61	
62	NCCLSymmetricMemoryContext::NCCLSymmetricMemoryContext(const int64_t& nccl_comm, const symmetric::cpu_comm_t& cpu_comm,
63	                                                       const int& num_ranks, const int& rank_idx,
64	                                                       const int64_t& num_bytes, const int64_t& num_cpu_bytes,
65	                                                       const bool& allow_hybrid_mode,
66	                                                       const int& sl_idx, const int& num_allocated_qps):
67	    rank_idx(rank_idx), num_ranks(num_ranks), num_allocated_qps(num_allocated_qps) {
68	    if (get_env("EP_BUFFER_DEBUG", 0)) {
69	        int nccl_version;
70	        NCCL_CHECK(ncclGetVersion(&nccl_version));
71	        printf("DeepEP initialized with NCCL version: %d.%d.%d (loaded library)\n",
72	               nccl_version / 10000, (nccl_version % 10000) / 100, nccl_version % 100);
73	    }
74	
75	    // Reuse the NCCL communicator
76	    comm = reinterpret_cast<ncclComm_t>(nccl_comm);
77	
78	    // Print number of allocated QPs
79	    if (get_env<int>("EP_BUFFER_DEBUG"))
80	        printf("EP NCCL device communicator has %d allocated QPs\n", num_allocated_qps);
81	
82	    // Initialize NCCL device communicator
83	    ncclDevCommRequirements_t reqs = NCCL_DEV_COMM_REQUIREMENTS_INITIALIZER;
84	    if (num_ranks > 1 and get_env("EP_DISABLE_GIN", 0) == 0) {
85	        // Query NCCL supported Gin Type
86	        ncclCommProperties props = NCCL_COMM_PROPERTIES_INITIALIZER;
87	        NCCL_CHECK(ncclCommQueryProperties(comm, &props));
88	        EP_HOST_ASSERT(
89	            (allow_hybrid_mode ? props.railedGinType : props.ginType) != NCCL_GIN_TYPE_NONE and
90	            "NCCL GIN is unavailable. This is usually due to a network configuration issue, "
91	            "such as `allow_hybrid_mode=0` (disable direct RDMA kernels) in multi-plane network.");
92	
93	        reqs.ginContextCount = num_allocated_qps;
94	        reqs.ginExclusiveContexts = true;
95	        reqs.ginQueueDepth = kGinQPDepth;
96	        reqs.ginTrafficClass = sl_idx;
97	        // Customized RDMA barrier needs extra signals
98	        reqs.ginSignalCount = num_ranks + 2 * 2;
99	        reqs.ginConnectionType = allow_hybrid_mode ? NCCL_GIN_CONNECTION_RAIL: NCCL_GIN_CONNECTION_FULL;
100	    }
101	    NCCL_CHECK(ncclDevCommCreate(comm, &reqs, &dev_comm));
102	
103	    // Now we know the NVLink domain size
104	    num_nvl_ranks = dev_comm.lsaSize, nvl_rank_idx = dev_comm.lsaRank;
105	    num_rdma_ranks = num_ranks / num_nvl_ranks, rdma_rank_idx = rank_idx / num_nvl_ranks;
106	    EP_HOST_ASSERT(num_ranks % num_nvl_ranks == 0 and nvl_rank_idx == rank_idx % num_nvl_ranks);
107	    EP_HOST_ASSERT(rank_idx == rdma_rank_idx * num_nvl_ranks + nvl_rank_idx);
108	
109	    // Calculate scaleout/up domain size
110	    if (allow_hybrid_mode) {
111	        num_scaleout_ranks = num_rdma_ranks, num_scaleup_ranks = num_nvl_ranks;
112	        scaleout_rank_idx = rdma_rank_idx, scaleup_rank_idx = nvl_rank_idx;
113	    } else {
114	        num_scaleout_ranks = 1, num_scaleup_ranks = num_ranks;
115	        scaleout_rank_idx = 0, scaleup_rank_idx = rank_idx;
116	    }
117	    is_scaleup_nvlink = num_scaleup_ranks == num_nvl_ranks;
118	
119	    // Create symmetric memory
120	    // num_bytes = GPU + CPU, derive GPU portion
121	    this->symmetric_memory = symmetric::alloc(
122	        num_bytes - num_cpu_bytes, num_cpu_bytes,
123	        allow_hybrid_mode, num_scaleup_ranks, scaleout_rank_idx,
124	        cpu_comm);
125	
126	    // Create window
127	    // NOTES: `ncclCommWindowRegister` is collective: it internally calls bootstrapBarrier
128	    // across all ranks, so no explicit barrier is needed after this call.
129	    raw_window_ptr = this->symmetric_memory->ptr;
130	    this->num_gpu_bytes = this->symmetric_memory->num_gpu_bytes;
131	    this->num_cpu_bytes = this->symmetric_memory->num_cpu_bytes;
132	    NCCL_CHECK(ncclCommWindowRegister(comm, raw_window_ptr, this->symmetric_memory->num_bytes, &window, NCCL_WIN_STRICT_ORDERING));
133	    NCCL_CHECK(ncclGetLsaDevicePointer(window, 0, nvl_rank_idx, &mapped_window_ptr));
134	
135	    // Get LSA pointers for all LSA peers
136	    // TODO: check whether this is correct for network with RDMA
137	    nvl_window_ptrs.resize(num_nvl_ranks);
138	    for (int i = 0; i < num_nvl_ranks; ++ i)
139	        NCCL_CHECK(ncclGetLsaDevicePointer(window, 0, i, &nvl_window_ptrs[i]));
140	}
141	
142	void* NCCLSymmetricMemoryContext::get_sym_ptr(void* ptr, const int& dst_rank_idx) const {
143	    const auto offset = static_cast<uint8_t*>(ptr) - static_cast<uint8_t*>(mapped_window_ptr);
144	    return static_cast<uint8_t*>(nvl_window_ptrs[dst_rank_idx]) + offset;
145	}
146	
147	void NCCLSymmetricMemoryContext::finalize() {
148	    // Deregister window
149	    NCCL_CHECK(ncclCommWindowDeregister(comm, window));
150	    symmetric_memory.reset();
151	
152	    // Destroy device communicator
153	    NCCL_CHECK(ncclDevCommDestroy(comm, &dev_comm));
154	}
155	
156	}  // namespace deep_ep::nccl
